#!/usr/bin/env python3
"""Inject Sengekokujo (Macbeth expansion) art (a970-a985) into assets/assets.json. Idempotent.
   15 samurai character portraits + 1 deck box. Run from repo root (next to build.py):
       python3 apply_sengekokujo_art.py
"""
import json, os, sys
ROOT=os.path.dirname(os.path.abspath(__file__))
ASSETS=os.path.join(ROOT,"assets","assets.json")
ART={
    'a970': 'data:image/jpeg;base64,',
    'a971': 'data:image/jpeg;base64,',
    'a972': 'data:image/jpeg;base64,',
    'a973': 'data:image/jpeg;base64,',
    'a974': 'data:image/jpeg;base64,',
    'a975': 'data:image/jpeg;base64,',
    'a976': 'data:image/jpeg;base64,',
    'a977': 'data:image/jpeg;base64,',
    'a978': 'data:image/jpeg;base64,',
    'a979': 'data:image/jpeg;base64,',
    'a980': 'data:image/jpeg;base64,',
    'a981': 'data:image/jpeg;base64,',
    'a982': 'data:image/jpeg;base64,',
    'a983': 'data:image/jpeg;base64,',
    'a984': 'data:image/jpeg;base64,',
    'a985': 'data:image/jpeg;base64,'
}
def main():
    if not os.path.isfile(ASSETS): sys.exit("ERROR: assets/assets.json not found. Run from repo root.")
    data=json.load(open(ASSETS,encoding="utf-8"))
    a=s=0
    for k,v in ART.items():
        if data.get(k)==v: s+=1
        else: data[k]=v; a+=1
    json.dump(data,open(ASSETS,"w",encoding="utf-8"))
    print(f"Sengekokujo art: {a} written, {s} already present (a970-a985).")
    print("Next: python3 build.py")
if __name__=="__main__": main()
